properties.formula:
var text DesignReview =
If(ToText([Project - CAD Design Approved])<>"",
    If([Project - CAD Design Approved]>=Date(2024,11,25),If(not(IsNull([Project - Design Audit Completed])), ToText(ToDate([Project - Design Audit Completed])+Days([# of Attempts])),""),ToText([Project - CAD Design Approved]+Days([# of Attempts]))));

var date initialcall = ToDate([Project - Sales Date]+Days([# of Attempts]));

var text WelcomeCall = If(ToText([Project - Welcome Call Completed])="",
    If(ToText([Project - Welcome Call Scheduled])<>""   
    ,ToText(ToDate([Project - Welcome Call Scheduled])+Days
    ([# of Attempts])))
);

var text PermitSubmitted = If(ToText([Project - Permit Submitted])<>"",ToText([Project - Permit Submitted]+Days([# of Attempts])),"");

var text PermitReceived = If(ToText([Project - Permit Approved])<>"",ToText([Project - Permit Approved]+Days([# of Attempts])),"");

var text InstallSchedule = If(ToText([Project - Install Scheduled Date])<>"",ToText([Project - Install Scheduled Date]+Days([# of Attempts])),"");

var text InstallWIP = 
If(ToText([Project - Install Scheduled Date])<>"",
If(Today()-[Project - Install Scheduled Date]>Days(1),
If(IsNull([Project - Install Completed Date]),ToText([Project - Install Scheduled Date]+Days([# of Attempts])))));

var text InstallComplete = If(ToText([Project - Install Completed Date])<>"",ToText([Project - Install Completed Date]+Days([# of Attempts])),"");

var date inspectiondate = If(IsNull([Project - Task: Inspection Scheduled Date/Time]),[Project - Inspection Scheduled Date],ToDate([Project - Task: Inspection Scheduled Date/Time]));

var text InspectionScheduled = If(ToText([Project - Inspection Scheduled Date])<>"",ToText($inspectiondate+Days([# of Attempts])),"");

var text InspectionComplete = If(ToText([Project - Passing Inspection Completed Date])<>"" or ToText([Project - Max Passing Inspection Recorded Date])<>"",ToText(Max([Project - Passing Inspection Completed Date],[Project - Max Passing Inspection Recorded Date])+Days([# of Attempts])),"");

var text PTOSubmitted = If(ToText([Project - PTO Submitted Date])<>"",ToText([Project - PTO Submitted Date]+Days([# of Attempts])),"");

var text PTOApproved = If(ToText([Project - PTO Approved Date])<>"",ToText([Project - PTO Approved Date]+Days([# of Attempts])),"");

var text Repcancel = If(ToText([Project - Status])<>"Pending Cancel",ToText([Date Created]+Days([# of Attempts])),"");

var date staledate = ToDate([Project - Maximum PC Outreach Completed Date])+Days([# of Attempts]+10);

//need to add Permit Follow Up Task and Install Update

var date duedate = If(
[Outreach Status]="Complete",ToDate(""),
[Outreach Status]="Complete - No Answer",ToDate(""),
ToText([Placeholder Due Date])<>"",[Placeholder Due Date],
[Touchpoint Name]="Initial Outreach", $initialcall,
[Touchpoint Name]="Welcome Call", ToDate($welcomecall),
[Touchpoint Name]="Rep Cancel Request",ToDate($Repcancel),
[Touchpoint Name]="Design Approval", ToDate($DesignReview),
[Touchpoint Name]="Permit Submitted", ToDate($PermitSubmitted),
[Touchpoint Name]="Permit Received", ToDate($PermitReceived),
[Touchpoint Name]="Install Schedule", ToDate($installschedule),
[Touchpoint Name]="Install WIP",ToDate($installWIP),
[Touchpoint Name]="Install Complete", ToDate($installcomplete),
[Touchpoint Name]="Inspection Scheduled", ToDate($InspectionScheduled),
[Touchpoint Name]="Inspection Complete", ToDate($InspectionComplete),
[Touchpoint Name]="PTO Submitted", ToDate($PTOsubmitted),
[Touchpoint Name]="PTO Approval", ToDate($PTOApproved),
[Touchpoint Name]="Cancel Request",Today(),
[Touchpoint Name]="Cancel Reactivation",Today(),
[Touchpoint Name]="Check-In",$staledate
);

If(Contains([Project Coordinator],"Gianna"),If($duedate>Date(2024,6,1),$duedate),$duedate)

var text DesignReview = If(ToText([Project - CAD Design Approved])<>"",ToText([Project - CAD Design Approved]+Days([# of Attempts])),"");
var text PermitSubmitted = If(ToText([Project - Permit Submitted])<>"",ToText([Project - Permit Submitted]+Days([# of Attempts])),"");
var text PermitReceived = If(ToText([Project - Permit Approved])<>"",ToText([Project - Permit Approved]+Days([# of Attempts])),"");
var text InstallSchedule = If(ToText([Project - Install Scheduled Date])<>"",ToText([Project - Install Scheduled Date]+Days([# of Attempts])),"");
var text InstallComplete = If(ToText([Project - Install Completed Date])<>"",ToText([Project - Install Completed Date]+Days([# of Attempts])),"");
var text InspectionScheduled = If(ToText([Project - Inspection Scheduled Date])<>"",ToText([Project - Inspection Scheduled Date]+Days([# of Attempts])),"");
var text InspectionComplete = If(ToText([Project - Passing Inspection Completed Date])<>"",ToText([Project - Passing Inspection Completed Date]+Days([# of Attempts])),"");
var text PTOSubmitted = If(ToText([Project - PTO Submitted Date])<>"",ToText([Project - PTO Submitted Date]+Days([# of Attempts])),"");
var text PTOApproved = If(ToText([Project - PTO Approved Date])<>"",ToText([Project - PTO Approved Date]+Days([# of Attempts])),"");

//need to add Permit Follow Up Task and Install Update

If(
ToText([Placeholder Due Date])<>"",[Placeholder Due Date],
[Touchpoint Name]="Design Approval", ToDate($DesignReview),
[Touchpoint Name]="Permit Submitted", ToDate($PermitSubmitted),
[Touchpoint Name]="Permit Received", ToDate($PermitReceived),
[Touchpoint Name]="Install Schedule", ToDate($installschedule),
[Touchpoint Name]="Install Complete", ToDate($installcomplete),
[Touchpoint Name]="Inspection Scheduled", ToDate($InspectionScheduled),
[Touchpoint Name]="Inspection Complete", ToDate($InspectionComplete),
[Touchpoint Name]="PTO Submitted", ToDate($PTOsubmitted),
[Touchpoint Name]="PTO Approved", ToDate($PTOApproved),
[Touchpoint Name]="Cancel Reactivation",[Cancel Request/Reactivation Date],
[Touchpoint Name]="Cancel Request",[Cancel Request/Reactivation Date]
)
